def process_graph(graph_data):
    graph_copy = graph_data.copy()

    # Find the control domain node
    control_domain_node = None
    for node in graph_copy.nodes(data=True):
        if node[1]['name'] == 'ju1.a2.dom' and 'EK_CONTROL_DOMAIN' in node[1]['type']:
            control_domain_node = node[0]
            break

    if not control_domain_node:
        # Return empty result if control domain not found
        return {
            'type': 'list',
            'data': [],
            'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
        }

    # Find all child nodes connected to the control domain
    child_nodes = []
    for edge in graph_copy.edges(data=True):
        if edge[0] == control_domain_node and edge[2]['type'] == ['RK_CONTAINS']:
            child_node_name = edge[1]
            child_node = None
            for node in graph_copy.nodes(data=True):
                if node[0] == child_node_name:
                    child_node = node
                    break

            if child_node:
                # Calculate total physical capacity for this child node
                total_capacity = 0
                # Check if it's a PORT node (leaf node)
                if 'EK_PORT' in child_node[1]['type']:
                    total_capacity = child_node[1].get('physical_capacity_bps', 0)
                else:
                    # For non-port nodes, we need to traverse down the hierarchy
                    # We'll find all port nodes within this node's subtree
                    visited = set()
                    def traverse_and_sum(node_id):
                        nonlocal total_capacity, visited
                        if node_id in visited:
                            return
                        visited.add(node_id)

                        node_data = graph_copy.nodes[node_id]
                        if 'EK_PORT' in node_data['type']:
                            total_capacity += node_data.get('physical_capacity_bps', 0)
                        else:
                            # Traverse children
                            for successor in graph_copy.successors(node_id):
                                if graph_copy.has_edge(node_id, successor):
                                    edge_data = graph_copy.get_edge_data(node_id, successor)
                                    if edge_data and edge_data['type'] == ['RK_CONTAINS']:
                                        traverse_and_sum(successor)

                    traverse_and_sum(child_node[0])

                child_nodes.append((child_node[1]['name'], total_capacity))

    # Sort by physical capacity descending
    child_nodes.sort(key=lambda x: x[1], reverse=True)

    return {
        'type': 'list',
        'data': child_nodes,
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }

