    control_domain_node = None
    for node in graph_copy.nodes(data=True):
        if node[1]['name'] == 'ju1.a2.dom' and 'EK_CONTROL_DOMAIN' in node[1]['type']:
            control_domain_node = node[0]
            break

    if control_domain_node is None:
        # Return empty result if control domain not found
        return {
            'type': 'list',
            'data': [],
            'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
        }

    # Find all child nodes of this control domain
    child_nodes = []
    for edge in graph_copy.edges(data=True):
        if edge[0] == control_domain_node and edge[2]['type'] == ['RK_CONTAINS']:
            child_nodes.append(edge[1])

    # Calculate physical capacity for each child node
    capacities = []
    for node_name in child_nodes:
        node = graph_copy.nodes[node_name]
        total_capacity = 0

        # Check if node itself is a port
        if 'EK_PORT' in node['type']:
            total_capacity = node.get('physical_capacity_bps', 0)
        else:
            # For other node types, we need to traverse down to ports
            # We'll do a DFS to collect all ports under this node
            visited = set()
            stack = [node_name]

            while stack:
                current_node = stack.pop()
                if current_node in visited:
                    continue
                visited.add(current_node)

                current_node_data = graph_copy.nodes[current_node]

                # Add port capacities at this level
                if 'EK_PORT' in current_node_data['type']:
                    total_capacity += current_node_data.get('physical_capacity_bps', 0)
                else:
                    # Continue traversing children (only direct contains relationships)
                    for edge in graph_copy.edges(data=True):
                        if edge[0] == current_node and edge[2]['type'] == ['RK_CONTAINS']:
                            stack.append(edge[1])

        capacities.append((node['name'], total_capacity))

    # Sort by physical capacity descending
    capacities.sort(key=lambda x: x[1], reverse=True)

    return {
        'type': 'list',
        'data': capacities,
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }

